class TrieNode:
    def __init__(self):
        self.children: Dict[int:TrieNode] = {}
        self.isEndOfWord: bool = False

    def insert(self, key: str) -> None:
        curr: TrieNode = self
        for c in key:
            index: int = ord(c) - ord('a')
            if index in curr.children:
                new_node = curr.children[index]
            else:
                new_node = TrieNode()
                curr.children[index] = new_node

            curr = new_node
        curr.isEndOfWord = True

    def search(self, key: str) -> bool:
        curr: TrieNode = self
        for c in key:
            index: int = ord(c) - ord('a')
            if index not in curr.children:
                return False

            curr = curr.children[index]
        return curr.isEndOfWord

    def ch_search(self, key: str) -> None|TrieNode:
        index: int = ord(key) - ord('a')
        if index in self.children:
            return self.children[index]
        else:
            return None


class Solution:
    def findWords(self, board: List[List[str]], words: List[str]) -> List[str]:
        result: List[str] = []

        trie:TrieNode = TrieNode()
        for word in words:
            trie.insert(word)


        def dfs(check_board: List[List[bool]], x: int, y: int, this_trie: TrieNode, word: str) -> None:
            if x > 0 and check_board[x - 1][y]:
                current_trie: TrieNode = this_trie.ch_search(board[x - 1][y])
                if current_trie:
                    new_word = word + board[x - 1][y]
                    if current_trie.isEndOfWord:
                        result.append(new_word)
                    check_board[x - 1][y] = False
                    dfs(check_board, x - 1, y, current_trie, new_word)
                    check_board[x - 1][y] = True

            if y > 0 and check_board[x][y - 1]:
                current_trie: TrieNode = this_trie.ch_search(board[x][y - 1])
                if current_trie:
                    new_word = word + board[x][y - 1]
                    if current_trie.isEndOfWord:
                        result.append(new_word)
                    check_board[x][y - 1] = False
                    dfs(check_board, x, y  - 1, current_trie, new_word)
                    check_board[x][y - 1] = True

            if x + 1 < len(check_board) and check_board[x + 1][y]:
                current_trie: TrieNode = this_trie.ch_search(board[x + 1][y])
                if current_trie:
                    new_word = word + board[x + 1][y]
                    if current_trie.isEndOfWord:
                        result.append(new_word)
                    check_board[x + 1][y] = False
                    dfs(check_board, x + 1, y, current_trie, new_word)
                    check_board[x + 1][y] = True

            if y + 1 < len(check_board[0]) and check_board[x][y + 1]:
                current_trie: TrieNode = this_trie.ch_search(board[x][y + 1])
                if current_trie:
                    new_word = word  + board[x][y + 1]
                    if current_trie.isEndOfWord:
                        result.append(new_word)
                    check_board[x][y + 1] = False
                    dfs(check_board, x, y + 1, current_trie, new_word)
                    check_board[x][y + 1] = True

        checking_board: list[list[bool]] = [[True for _ in range(len(board[0]))] for _ in range(len(board))]
        for x in range(len(board)):
            for y in range(len(board[0])):
                current_trie: TrieNode = trie.ch_search(board[x][y])
                if current_trie:
                    if current_trie.isEndOfWord:
                        result.append(board[x][y])
                    dfs(checking_board, x, y, current_trie, board[x][y] + "")

        return result

